mapper.select:
SELECT emp_seq, employeeId, password, role, active, emp_nm FROM employee WHERE 1=1
AND EMP_NM LIKE CONCAT('%', #{keyword}, '%')
ORDER BY emp_seq ASC LIMIT #{offset}, #{size}

mapper.update:
UPDATE employee
SET active = CASE WHEN active = 1 THEN 0 ELSE 1 END
WHERE emp_seq = #{emp_seq}

mapper.insert:
INSERT INTO employee (
emp_seq
, employeeId
, password
, active
, emp_nm
, phone
, birth
, deptName
, position
, role
, hireDate
, resignDate
) VALUES (
(SELECT seq FROM (
SELECT COALESCE(MAX(emp_seq), 0) + 1 AS seq
FROM employee
) AS t)
, #{employeeId}
, #{password}
, 1
, #{empNm}
, #{phone}
, #{birth}
, #{deptName}
, #{position}   
, #{role}
, #{hireDate}
, #{resignDate}
)
